// Agent 6: format output â€” plain markdown (not JSON like Agent 5)
// Mode: Run Once for All Items
// Propagates structured error from Call LLM on failure.
// Falls back to original resume markdown when refinement fails or is unusable,
// so downstream still has a valid resume to work with.

const callLLM = $('Call LLM').first().json;
const originalMarkdown = $('Set Inputs').first().json.resume_markdown || '';

// Call LLM failed â€” propagate error, fall back to original
if (callLLM.success === false) {
  console.log(`[Agent 6] LLM call failed: ${callLLM.error?.category || 'unknown'} â€” ${callLLM.error?.message || 'no message'}`);
  console.log(`[Agent 6] Falling back to original resume markdown (${originalMarkdown.length} chars)`);
  return {
    json: {
      success: false,
      resume_markdown: originalMarkdown,
      refined: false,
      tokens: { input: callLLM.input_tokens || 0, output: callLLM.output_tokens || 0 },
      cached_input_tokens: callLLM.cached_input_tokens || 0,
      cache_write_tokens: callLLM.cache_write_tokens || 0,
      model_used: callLLM.model_used || 'unknown',
      provider_used: callLLM.provider_used || 'unknown',
      errors: [...(callLLM.errors || [])],
      error: callLLM.error || {
        category: 'unknown',
        type: 'unknown',
        message: 'Call LLM returned success: false with no error object',
        provider: callLLM.provider_used || 'unknown',
        model: callLLM.model_used || 'unknown'
      }
    }
  };
}

// Normal path: parse refined markdown from content
const response = $input.item.json;
const text = response.text || response.content || response.response || response.output_text || response.completion || '';

const parseErrors = [];
let refinedMarkdown = '';

if (!text) {
  parseErrors.push(`No text returned from Call LLM. Keys: ${Object.keys(response).join(', ')}`);
  console.log(`[Agent 9] ${parseErrors[parseErrors.length - 1]}`);
} else {
  refinedMarkdown = String(text).trim();
  // Strip markdown code fences if the LLM wrapped the output (defensive)
  refinedMarkdown = refinedMarkdown
    .replace(/^```(?:markdown|md)?\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
}

// Quality checks: too short OR identical to input
const tooShort = refinedMarkdown.length <= 100;
const identicalToOriginal = refinedMarkdown.length > 0 && refinedMarkdown === originalMarkdown;
const refined = !tooShort && !identicalToOriginal;

let error = null;
if (parseErrors.length > 0) {
  error = {
    category: 'output_quality',
    type: 'empty_output',
    message: parseErrors.join('; '),
    provider: callLLM.provider_used || 'unknown',
    model: callLLM.model_used || 'unknown'
  };
} else if (tooShort) {
  parseErrors.push(`Refined output too short (${refinedMarkdown.length} chars)`);
  error = {
    category: 'output_quality',
    type: 'short_output',
    message: parseErrors[parseErrors.length - 1],
    provider: callLLM.provider_used || 'unknown',
    model: callLLM.model_used || 'unknown'
  };
} else if (identicalToOriginal) {
  parseErrors.push('Refined output identical to original');
  error = {
    category: 'output_quality',
    type: 'no_change',
    message: parseErrors[parseErrors.length - 1],
    provider: callLLM.provider_used || 'unknown',
    model: callLLM.model_used || 'unknown'
  };
}

const success = refined;

console.log(`[Agent 9] Refined: ${refined}, length: ${refinedMarkdown.length} chars`);
console.log(`[Agent 9] Tokens: ${callLLM.input_tokens || 0}in + ${callLLM.output_tokens || 0}out + ${callLLM.cached_input_tokens || 0}cached + ${callLLM.cache_write_tokens || 0}cache_write`);

return {
  json: {
    success,
    resume_markdown: refined ? refinedMarkdown : originalMarkdown,
    refined,
    tokens: { input: callLLM.input_tokens || 0, output: callLLM.output_tokens || 0 },
    cached_input_tokens: callLLM.cached_input_tokens || 0,
    cache_write_tokens: callLLM.cache_write_tokens || 0,
    model_used: callLLM.model_used || 'unknown',
    provider_used: callLLM.provider_used || 'unknown',
    errors: parseErrors,
    error
  }
};

// Set Inputs â€” Agent 9: Fine Refiner (user-instruction driven)
// Model/provider/max_tokens are config-only (config.*_refiner), like every other agent.
// The dashboard no longer sends provider/model/max_tokens; config is the single source of truth.
const trigger = $input.item.json;

function strip(val) {
  if (val === null || val === undefined) return '';
  if (typeof val !== 'string') return val;
  let cleaned = val;
  while (cleaned.length > 0 && cleaned.charAt(0) === '=') cleaned = cleaned.substring(1);
  return cleaned;
}

const config = trigger.config || {};
const systemPrompt = strip(trigger.system_prompt);
const descriptionHtml = strip(trigger.description_html);
const resumeMarkdown = strip(trigger.resume_markdown);
const masterDoc = strip(trigger.master_doc);
const refinementInstructions = strip(trigger.user_command);

// Optional prior verifier (from the previous version). May arrive as Object or JSON-string.
let verifier = trigger.verifier;
if (typeof verifier === 'string') {
  let raw = verifier;
  while (raw.length > 0 && raw.charAt(0) === '=') raw = raw.substring(1);
  try { verifier = JSON.parse(raw); }
  catch (e) { console.log('[Agent 9 Set Inputs] verifier not parseable JSON, defaulting to empty'); verifier = {}; }
}
verifier = verifier || {};
if (verifier.result && typeof verifier.result === 'object') verifier = verifier.result;

// Provider / model / max_tokens are config-only (config.*_refiner). Throw loud if missing.
const provider = strip(config.provider_refiner);
if (!provider) {
  throw new Error('[Agent 9] config.provider_refiner is required. Set it in your config sheet (anthropic | openai | gemini).');
}
const model = strip(config.model_refiner);
if (!model) {
  throw new Error('[Agent 9] config.model_refiner is required. Set it in your config sheet.');
}
const maxTokens = Number(config.max_tokens_refiner);
if (!maxTokens || Number.isNaN(maxTokens)) {
  throw new Error('[Agent 9] config.max_tokens_refiner is required and must be a number.');
}

if (!refinementInstructions) {
  throw new Error('[Agent 9] refinement_instructions is required for refine mode.');
}

console.log(`[Agent 9 Set Inputs] resume: ${resumeMarkdown.length} chars, master_doc: ${masterDoc.length} chars, instructions: ${refinementInstructions.length} chars, prior verifier issues: ${(verifier.issues || []).length}, provider: ${provider}, model: ${model}`);

return {
  json: {
    config,
    system_prompt: systemPrompt,
    description_html: descriptionHtml,
    resume_markdown: resumeMarkdown,
    master_doc: masterDoc,
    refinement_instructions: refinementInstructions,
    verifier,
    provider,
    model,
    max_tokens: maxTokens
  }
};

// Build Prompt â€” Agent 9: Fine Refiner (user-instruction driven)
const input = $input.item.json;
const systemPrompt = input.system_prompt || '';
const masterDoc = input.master_doc || '';
const resumeMarkdown = input.resume_markdown || '';
const verifier = input.verifier || {};
const descriptionHtml = input.description_html || '';
const instructions = input.refinement_instructions || '';

if (!systemPrompt || systemPrompt.length < 200) {
  throw new Error(`[Agent 9] system_prompt missing or too short (${systemPrompt.length} chars). Check Prompt Loader / prompts tab and orchestrator mapping.`);
}
if (!resumeMarkdown || resumeMarkdown.length < 100) {
  throw new Error(`[Agent 9] resume_markdown missing or too short (${resumeMarkdown.length} chars). Check parent_resume_markdown in the request.`);
}
if (!masterDoc || masterDoc.length < 200) {
  throw new Error(`[Agent 9] master_doc missing or too short (${masterDoc.length} chars). Check Data Loader output.`);
}
if (!instructions) {
  throw new Error('[Agent 9] refinement_instructions missing â€” required for refine mode.');
}

const OUTPUT_CONTRACT = `## OUTPUT CONTRACT
- Output ONLY the refined resume markdown.
- Do NOT wrap in JSON or any envelope.
- Do NOT prepend or append commentary, preamble, or summary.
- Start directly with the resume's first line (the tagline beginning with '# ').
- Preserve the original markdown structure unless the instructions explicitly ask to restructure.
- Output must be 100% faithful to the master doc â€” no invented facts, no embellishments.
- Apply the candidate's revision instructions as the primary driver.

## Professional Experience format (required for rendering)

Each role must follow this exact structure:

### Company Name | Role Title | Start Year â€“ End Year

*One-line scope summary. No metrics, no bullets.*

- Bullet (action verb start, quantified where possible)

Role header line must:
- Start with \`### \` (the h3 marker â€” required for proper styling)
- Use \` | \` (space-pipe-space) as the separator between company, title, and years
- Use \` â€“ \` (en-dash with spaces) between start and end years
- Contain NO bold or italic markdown â€” the renderer adds styling

The scope line directly under the role header must:
- Be wrapped in \`*...*\` for italic
- Be one line, no wrapping
- Contain NO metrics and NO bullet marker (\`-\` or \`*\`)`;

// Prior verifier is optional â€” include the block only if it carries findings.
const hasVerifier = verifier && Array.isArray(verifier.issues) && verifier.issues.length > 0;
const verifierBlock = hasVerifier
  ? `\n\n# PRIOR VERIFIER FINDINGS (from the previous version â€” correct any that still apply, non-negotiable)\n${JSON.stringify(verifier, null, 2)}`
  : '';

const userMessage = `# JOB DESCRIPTION
${descriptionHtml}

# CANDIDATE MASTER DOCUMENT
${masterDoc}

# CURRENT RESUME (to be revised)
${resumeMarkdown}

# REVISION INSTRUCTIONS (from the candidate â€” the primary driver of this revision)
${instructions}${verifierBlock}

${OUTPUT_CONTRACT}`;

console.log(`[Agent 9 Build Prompt] system_prompt: ${systemPrompt.length} chars, user_message: ${userMessage.length} chars, instructions: ${instructions.length} chars, prior verifier: ${hasVerifier ? verifier.issues.length + ' issues' : 'none'}`);

return {
  json: {
    system_prompt: systemPrompt,
    user_message: userMessage,
    provider: input.provider,
    model: input.model,
    max_tokens: input.max_tokens || 8192
  }
};
